/**
 * import-nail-catalog.mjs
 *
 * Reads the _catalog.json generated by classify-nail-styles.mjs,
 * copies images into public/uploads/nail-styles/,
 * and inserts records into the nail_styles table via Drizzle.
 *
 * Usage:
 *   node scripts/import-nail-catalog.mjs
 *
 * Optional: dry run (no DB writes, no file copies)
 *   node scripts/import-nail-catalog.mjs --dry-run
 */

import { readFileSync, copyFileSync, mkdirSync, existsSync } from "fs";
import { join, basename, dirname, extname } from "path";
import { fileURLToPath } from "url";
import { neon } from "@neondatabase/serverless";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, "..");
const DRY_RUN = process.argv.includes("--dry-run");

if (DRY_RUN) console.log("🔍 DRY RUN — no writes");

// ─── Config ───────────────────────────────────────────────────────────────────

const CATALOG_FILE =
  "C:/Users/PC/Desktop/caiena_instagram_pipeline_20260430_222913/data/classified/_catalog.json";

const PUBLIC_UPLOADS = join(ROOT, "public", "uploads", "nail-styles");

// ─── DB ───────────────────────────────────────────────────────────────────────

const envContent = readFileSync(join(ROOT, ".env.local"), "utf-8");
const dbUrlMatch = envContent.match(/DATABASE_URL=(.+)/);
if (!dbUrlMatch) {
  console.error("❌ DATABASE_URL not found in .env.local");
  process.exit(1);
}
const sql = neon(dbUrlMatch[1].trim());

// ─── Main ─────────────────────────────────────────────────────────────────────

async function main() {
  if (!existsSync(CATALOG_FILE)) {
    console.error(`❌ Catalog not found: ${CATALOG_FILE}`);
    console.error("   Run classify-nail-styles.mjs first.");
    process.exit(1);
  }

  const catalog = JSON.parse(readFileSync(CATALOG_FILE, "utf-8"));
  console.log(`📋 ${catalog.length} entries in catalog`);

  mkdirSync(PUBLIC_UPLOADS, { recursive: true });

  let imported = 0;
  let skipped = 0;

  for (let i = 0; i < catalog.length; i++) {
    const entry = catalog[i];

    // Copy image to public/uploads/nail-styles/
    const ext = extname(entry.originalFile);
    const destFilename = `ig-${i + 1}${ext}`;
    const destPath = join(PUBLIC_UPLOADS, destFilename);
    const publicUrl = `/uploads/nail-styles/${destFilename}`;

    if (!existsSync(entry.thumbnailSrc)) {
      console.warn(`  ⚠️  Source not found: ${entry.thumbnailSrc}`);
      skipped++;
      continue;
    }

    if (!DRY_RUN) {
      copyFileSync(entry.thumbnailSrc, destPath);

      await sql`
        INSERT INTO nail_styles
          (name, description, category, prompt, thumbnail_url, color, acabado, forma, estilo, active, sort_order)
        VALUES (
          ${entry.name},
          ${entry.description},
          ${entry.category},
          ${entry.prompt},
          ${publicUrl},
          ${entry.color ?? null},
          ${entry.acabado ?? null},
          ${entry.forma ?? null},
          ${entry.estilo ?? null},
          true,
          ${i}
        )
      `;
    }

    imported++;
    console.log(`[${i + 1}/${catalog.length}] ${DRY_RUN ? "(dry)" : "✅"} ${entry.name} → ${entry.category} | ${publicUrl}`);
  }

  console.log(`\n✨ Done — ${imported} imported, ${skipped} skipped`);
  if (DRY_RUN) console.log("   (no changes made — remove --dry-run to apply)");
}

main().catch((err) => {
  console.error("Fatal:", err);
  process.exit(1);
});
